module tb_RefModule;

    bool simulation_passed = 1;

    // Inputs (shared between DUT and golden)
    logic [254:0] in;

    // Outputs (separate wires for DUT and golden)
    logic [7:0] out_dut;
    logic [7:0] out_golden;
    // Reset signal (if not already defined in inputs)
    logic rst = 1'b0;  // Default to low

    // Counters for tracking test statistics
    longint out_total_checks = 0;
    longint out_error_checks = 0;


    // Clock generation (if sequential)

    // DUT instantiation
    TopModule dut (
        .in(in),        .out(out_dut)    );

    // Golden reference instantiation
    RefModule golden (
        .in(in),        .out(out_golden)    );
    // Randomize data inputs
    task automatic randomize_data_inputs();
    ;
        in = {31'($urandom), 32'($urandom), 32'($urandom), 32'($urandom), 32'($urandom), 32'($urandom), 32'($urandom), 32'($urandom)};
    endtask

    // Compare outputs
    task automatic compare_outputs();
    ;
    	// Verification: XORs on the right makes any X in good_vector match anything, but X in dut_vector will only match X.
        // assign tb_match = ( { out_ref } === ( { out_ref } ^ { out_dut } ^ { out_ref } ) || ( {out_ref} === {out_dut} ) );

        out_total_checks++;
        if (out_golden === (out_golden ^ out_dut ^ out_golden) || ( out_golden === out_dut)) begin 
        end else begin
            out_error_checks++;
            simulation_passed = 0;
        end
    endtask

    // Reset task

    // Drive default zeros
    initial begin
        in = '0;
    end

    // Main stimulus
    initial begin
        longint ctrl_iter;
        longint ctrl_iter_tmp;
        longint sample_iter;
        longint ctrl_out_iter;
        longint reset_iter;
        longint reset_test = 1;

        for (reset_iter = 0; reset_iter < reset_test; reset_iter++) begin
        for (ctrl_out_iter = 1; ctrl_out_iter <= 1024; ctrl_out_iter++) begin
            // Randomize data inputs
            randomize_data_inputs();
            #1; compare_outputs();
            // Enumerate control inputs across all combinations
            for (ctrl_iter = 0; ctrl_iter < (1 << 0); ctrl_iter++) begin
                // Assign control vector bits
                ctrl_iter_tmp = ctrl_iter;

                // Randomize data inputs
                for (sample_iter = 0; sample_iter < 1024; sample_iter += ctrl_out_iter) begin
                    randomize_data_inputs();
                    #1;

                    compare_outputs();
                end
            end
        end
        end

        // Print statistics for each output signal
        $display("\n=== Test Statistics ===");
        $display("out: %0d total checks, %0d errors (%.2f%% pass rate)", 
                 out_total_checks, 
                 out_error_checks, 
                 out_total_checks > 0 ? (100.0 * (out_total_checks - out_error_checks) / out_total_checks) : 0.0);
        $display("=======================\n");

        if (simulation_passed) begin
            $display("TB completed successfully.");
        end else begin
            $fatal(1, "TB found errors.");
        end
        $finish;
    end

    initial begin
        #100000000000; $fatal(1, "TB timed out.");
    end
endmodule

