    TopModule dut (
        .clk(clk),        .resetn(resetn),        .byteena(byteena),        .d(d),        .q(q_dut)    );

    // Golden reference instantiation
    RefModule golden (
        .clk(clk),        .resetn(resetn),        .byteena(byteena),        .d(d),        .q(q_golden)    );
    // Randomize data inputs
    task automatic randomize_data_inputs();
    ;
        d = 16'($urandom);
    endtask

    // Compare outputs
    task automatic compare_outputs();
    ;
    	// Verification: XORs on the right makes any X in good_vector match anything, but X in dut_vector will only match X.
        // assign tb_match = ( { out_ref } === ( { out_ref } ^ { out_dut } ^ { out_ref } ) || ( {out_ref} === {out_dut} ) );

        q_total_checks++;
        if (q_golden === (q_golden ^ q_dut ^ q_golden) || ( q_golden === q_dut)) begin 
        end else begin
            q_error_checks++;
            simulation_passed = 0;
        end
    endtask

    // Reset task
    task automatic do_reset();
        begin
            resetn = 1'b0;
            @(posedge clk); #1
            compare_outputs();
            resetn = 1'b1;
            #0.1;
            // @(posedge clk);
        end
    endtask

    task automatic do_async_reset();
        begin
            @(posedge clk); #0.1
            repeat (5) begin
                resetn = 1'b0;
                #0.1
                compare_outputs();
                resetn = 1'b1;
                #0.1
                compare_outputs();
            end
        end
    endtask

    // Drive default zeros
    initial begin
        clk = '0;
        resetn = '0;
        byteena = '0;
        d = '0;
