                    compare_outputs();

                    @(posedge clk); #1;
                    compare_outputs();
                    randomize_data_inputs();
                    #1;
                    compare_outputs();
                end
            end
        end
        end

        // Print statistics for each output signal
        $display("\n=== Test Statistics ===");
        $display("q: %0d total checks, %0d errors (%.2f%% pass rate)", 
                 q_total_checks, 
                 q_error_checks, 
