module RefModule (
  input clk,
  input reset,
  input data,
  output reg shift_ena,
  output reg counting,
  input done_counting,
  output reg done,
  input ack
);

  // typedef enum logic[3:0] {
  //   S, S1, S11, S110, B0, B1, B2, B3, Count, Wait
  // } States;
  localparam S = 4'b0000, S1 = 4'b0001, S11 = 4'b0010, S110 = 4'b0011;
  localparam B0 = 4'b0100, B1 = 4'b0101, B2 = 4'b0110, B3 = 4'b0111;
  localparam Count = 4'b1000, Wait = 4'b1001;

  logic [3:0] state, next;

  always_comb begin
    case (state)
      S: next = (data ? S1: S);
      S1: next = (data ? S11: S);
      S11: next = (data ? S11 : S110);
      S110: next = (data ? B0 : S);
      B0: next = B1;
      B1: next = B2;
      B2: next = B3;
      B3: next = Count;
      Count: next = (done_counting ? Wait : Count);
      Wait: next = (ack ? S : Wait);
      default: next = 'x;
    endcase
  end

  always @(posedge clk) begin
    if (reset) state <= S;
    else state <= next;
  end

  always_comb begin
    shift_ena = 0; counting = 0; done = 0;
    if (state == B0 || state == B1 || state == B2 || state == B3)
      shift_ena = 1;
    if (state == Count)
      counting = 1;
    if (state == Wait)
      done = 1;

    if (|state === 1'bx) begin
      {shift_ena, counting, done} = 'x;
    end

  end

endmodule

